INSERT INTO public.challenge_types (id, name, description, tutorial_illustration_url, is_active, created_at) VALUES
  ('4a5e7a4e-441a-40ee-9540-89c4979bd658', 'Cul sec 25cl', 'Le demi vient simplement du fait qu’il correspond à la moitié d’une pinte.', NULL, true, '2025-12-09 16:52:56.130627+00'),
  ('371140a5-8ce5-4037-8adb-8f35362771d4', 'Cul sec 50cl', 'Du latin pincta (« marquée/peinte »), car les récipients étaient autrefois marqués d’un trait indiquant la mesure pour servir les boissons.', NULL, true, '2026-03-13 16:44:40.179541+00'),
  ('2d3ad48c-e8cb-42b7-ab82-9e932b0ece93', 'Cul sec 1L', 'Venant du litron, une ancienne mesure de volume française utilisée avant la Révolution.', NULL, true, '2026-03-13 16:46:28.242235+00')
